INSERT INTO `movie` VALUES (1001,'Spider-Man: Across the Spider-Verse','After reuniting with Gwen Stacy, Brooklyn’s full-time Spider-Man is pulled into the Multiverse and meets the Spider Society. When their plans for a new threat clash, Miles is pushed against other Spider-People and must go his own way to protect the people he loves.',NULL,140,'2023-05-31','English',NULL,'PG','ACTIVE','https://image.tmdb.org/t/p/w780/8Vt6mWEReuy4Of61Lnj5Xj704m8.jpg','https://www.youtube.com/watch?v=shW9i6k8cB0'),(1002,'Dune: Part Two','Paul faces a mythic, revenge-driven struggle as he aligns with his allies and unites forces to challenge the conspirators who destroyed his family. Along the way, he must weigh love against a future he alone can foresee, trying to prevent catastrophe.',NULL,167,'2024-02-27','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/1pdfLvkbY9ohJlCjQH2CZjjYVvJ.jpg','https://www.youtube.com/watch?v=Way9Dexny3w'),(1003,'Spider-Man: Into the Spider-Verse','Brooklyn teenager Miles Morales juggles school and family when he’s unexpectedly bitten by a radioactive spider and gains powers he must learn to use. As he figures out who he wants to be, a super collider draws other Spider-powered allies into his world, escalating the stakes.',NULL,117,'2018-12-06','English',NULL,'PG','ACTIVE','https://image.tmdb.org/t/p/w780/iiZZdoQBEYBv6id8su7ImL0oCbD.jpg','https://www.youtube.com/watch?v=g4Hbz2jLxvQ'),(1004,'Avengers: Endgame','After the universe is left in ruins, the remaining allies must come together again to undo the damage and restore order. With consequences hanging in the balance, they face an enormous challenge in order to bring things back once and for all.',NULL,181,'2019-04-24','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/ulzhLuWrPK07P1YkdWQLZnQh1JL.jpg','https://www.youtube.com/watch?v=TcMBFSGVi1c'),(1005,'Inception','A skilled thief who steals secrets by infiltrating people’s subconscious is offered a chance to change his life through one last job. The mission involves planting an idea inside a target’s mind, turning the work into a high-stakes dreamlike heist.',NULL,148,'2010-07-15','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/xlaY2zyzMfkhk0HSC5VUwzoZPU1.jpg','https://www.youtube.com/watch?v=YoHD9XEInc0'),(1006,'Godzilla Minus One','In postwar Japan, Godzilla brings fresh devastation to a landscape already scarred by war. With little help available, survivors band together and confront despair as they fight an unrelenting horror threatening their future.',NULL,125,'2023-11-03','Japanese',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/2E2WTX0TJEflAged6kzErwqX1kt.jpg','https://www.youtube.com/watch?v=OPIKfDGmNaM'),(1007,'Spider-Man: No Way Home','After his identity is revealed, Peter Parker can’t keep his regular life separate from the dangers of being a hero. Seeking help from a powerful sorcerer makes everything far worse, pulling him into a high-stakes conflict where he must figure out what it truly means to be Spider-Man.',NULL,148,'2021-12-15','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/1g0dhYtq4irTY1GPXvft6k4YLjm.jpg','https://www.youtube.com/watch?v=rt-2cxAiPJk'),(1008,'Mission: Impossible - Dead Reckoning Part One','Ethan Hunt and his IMF team race across the globe to find a powerful new weapon before it reaches the wrong hands. With humanity’s fate at stake and shadows from Ethan’s past closing in, they face a mysterious, all-powerful enemy as the hunt turns into a deadly showdown.',NULL,164,'2023-07-08','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/NNxYkU70HPurnNCSiCjYAmacwm.jpg','https://www.youtube.com/watch?v=2m1drlOZSDw'),(1009,'Mission: Impossible - Fallout','After a mission goes wrong, the world faces urgent consequences. With pressure from the CIA and danger closing in, an IMF team must race against time to stop a global catastrophe and prevent further harm.',NULL,147,'2018-07-25','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/AkJQpZp9WoNdj7pLYSj1L0RcMMN.jpg','https://www.youtube.com/watch?v=wb49-oV0F78'),(1010,'Batman: The Dark Knight Returns, Part 1','Batman has been out of action for years, but rising crime in Gotham pushes the aging Bruce Wayne back into the suit. As he returns to the fight, he faces a city that has grown darker and more dangerous, forcing him to prove he still belongs on the streets.',NULL,76,'2012-09-25','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/rVr2Tdp2LcL3DheXUrVN345Myhg.jpg','https://www.youtube.com/watch?v=0osGZGwFNkk'),(1011,'Avengers: Infinity War','The Avengers and their allies face a new cosmic threat determined to gather powerful artifacts and reshape reality. As the danger grows, heroes from across the universe are pulled into one desperate fight where the fate of Earth and everything beyond hangs in the balance.',NULL,149,'2018-04-25','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/7WsyChQLEftFiDOVTGkv3hFpyyt.jpg','https://www.youtube.com/watch?v=KU2APpDcTjI'),(1012,'Batman: Under the Red Hood','Years after a major tragedy, Batman hunts down a dangerous vigilante who shows up in Gotham with a different, more brutal approach. While the investigation tightens, Batman is forced to revisit painful memories as violence and moral debate escalate.',NULL,75,'2010-07-27','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/7lmHqHg1rG9b4U8MjuyQjmJ7Qm0.jpg','https://www.youtube.com/watch?v=Tmr14LHi-Rk'),(1013,'Dune: Part One','Paul must travel to a dangerous desert world where rival forces fight over control of the rare resource that shapes humanity’s future. Facing escalating conflict and inside threats, he’s driven to secure his family’s survival while confronting fear and an unsettling destiny.',NULL,155,'2021-09-15','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/gDzOcq0pfeCeqMBwKIJlSmQpjkZ.jpg','https://www.youtube.com/watch?v=n9xhJrPXop4'),(1014,'Batman: The Long Halloween, Part One','Following a brutal series of murders tied to major holidays, Gotham’s young vigilante sets out to hunt a mysterious serial killer. Working with police and the district attorney, the case turns into a tense investigation through Gotham’s criminal underworld.',NULL,85,'2021-06-21','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/sR7gppb0YGjwLvE6Vnj6wYv5MnW.jpg','https://www.youtube.com/watch?v=KFG-fx9u2PE'),(1015,'Interstellar','With Earth’s survival in jeopardy, a team of explorers uses a newly discovered wormhole to push beyond the limits of human space travel. Their mission is to seek answers and a possible new home as they navigate enormous distances and constant danger.',NULL,169,'2014-11-05','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/yQvGrMoipbRoddT0ZR8tPoR7NfX.jpg','https://www.youtube.com/watch?v=zSWdZVtXT7E'),(1016,'The Batman','In his second year fighting crime, Batman investigates corruption across Gotham City, only to find clues tied to his own family. His search collides with a serial killer who leaves puzzles and messages in the middle of a dangerous investigation.',NULL,177,'2022-03-01','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/74xTEgt7R36Fpooo50r9T25onhq.jpg','https://www.youtube.com/watch?v=mqqft2x_Aa4'),(1017,'Batman: The Long Halloween, Part Two','As a young vigilante in Gotham City, Batman presses forward in a tense hunt for a brutal serial killer. Meanwhile, the district attorney becomes entangled in a dangerous feud tied to the Falcone criminal family, raising the stakes across the city.',NULL,87,'2021-07-26','English',NULL,'R','ACTIVE','https://image.tmdb.org/t/p/w780/5X1n5q08mZ7NpNpxehMFODxfNYq.jpg','https://www.youtube.com/watch?v=n2hyHk1CYSo'),(1018,'The Avengers','When an unexpected enemy threatens global safety, Nick Fury recruits a high-powered team to pull the world back from the brink of disaster. Spanning the globe, the mission kicks off with a daring recruitment effort that brings unlikely heroes together.',NULL,143,'2012-04-25','English',NULL,'NR','ACTIVE','https://image.tmdb.org/t/p/w780/RYMX2wcKCBAr24UyPD7xwmjaTn.jpg','https://www.youtube.com/watch?v=eOrNdBpGMv8'),(1019,'Batman vs Teenage Mutant Ninja Turtles','Batman, Batgirl, and Robin team up with the Teenage Mutant Ninja Turtles to take on their shared threat. Together, they clash with The Shredder, who has apparently aligned with Ra’s Al Ghul and the League of Assassins.',NULL,87,'2019-03-31','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/yP3h0Pu8htyb9450mWJ9Vu1rU.jpg','https://www.youtube.com/watch?v=wpZPPrnEd_k'),(1020,'Batman vs. Robin','Damian Wayne struggles to follow his father’s no-killing rule as Gotham faces escalating threats. Amid the terror caused by the Dollmaker and the influence of the secretive Court of Owls, loyalty and ethics are pushed to their limits, testing how father and son deal with crime and responsibility.',NULL,80,'2015-04-03','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/aGp9XDXmVM5lCKHWtgBC15S7XLr.jpg','https://www.youtube.com/watch?v=6X0szCVmWI4'),(1021,'Spider-Man: Homecoming','After the events of Captain America: Civil War, a teenager in Queens tries to juggle high school life with fighting crime as a new threat rises. With help from his mentor, he faces the Vulture while learning what it really means to be a hero.',NULL,133,'2017-07-05','English',NULL,'NR','ACTIVE','https://image.tmdb.org/t/p/w780/c24sv2weTHPsmDa7jEMN0m2P3RT.jpg','https://www.youtube.com/watch?v=U0D3AOldjMU'),(1022,'Mission: Impossible - Rogue Nation','A top spy unit faces its most impossible mission yet, targeting an international rogue organization determined to destroy the agency. With authority shutting them down, the team must track the threat and disrupt its plans before it escalates worldwide.',NULL,131,'2015-07-28','English',NULL,'NR','ACTIVE','https://image.tmdb.org/t/p/w780/fRJLXQBHK2wyznK5yZbO7vmsuVK.jpg','https://www.youtube.com/watch?v=pXwaKB7YOjw'),(1023,'Spider-Man: Far from Home','Peter Parker and friends head to Europe for a summer trip, but the vacation is quickly interrupted. He must team up with Nick Fury to help uncover a mystery behind creatures causing natural disasters and widespread destruction across the continent.',NULL,129,'2019-06-28','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/4q2NNj4S5dG2RLF9CpXsej7yXl.jpg','https://www.youtube.com/watch?v=Nt9L1jCKGnE'),(1024,'Avatar: The Way of Water','More than a decade after the first film, the Sully family tries to carve out a safe life as fresh danger closes in. Forced to flee and adapt to a new ocean world, they face escalating threats while doing everything possible to protect one another.',NULL,192,'2022-12-14','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/t6HIqrRAclMCA60NsSmeqe9RmNV.jpg','https://www.youtube.com/watch?v=jOHCmLUng-Q'),(1025,'Joker','In 1980s Gotham City, a struggling stand-up comedian spirals deeper into chaos and crime as his mental state collapses. Pushed by life’s setbacks, he becomes an infamous, unpredictable figure in the city’s dark underbelly.',NULL,122,'2019-10-01','English',NULL,'NR','ACTIVE','https://image.tmdb.org/t/p/w780/udDclJoHjfjb8Ekgsd4FDteOkCU.jpg','https://www.youtube.com/watch?v=zAGVQLHvwOY'),(1026,'Avatar','In the 22nd century, a paraplegic Marine is sent to the moon Pandora for a high-stakes mission, but he finds himself questioning his orders. As he gets pulled into an alien civilization, the conflict grows between corporate interests and protecting a living world.',NULL,162,'2009-12-16','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/gKY6q7SjCkAU6FqvqWybDYgUKIF.jpg','https://www.youtube.com/watch?v=5PSNL1qE6VY'),(1027,'Superman','Superman is already an established hero in Metropolis when a new threat pushes him to face growing public doubt and rising tension around his place in the world. As he balances his life as a reporter and a defender, he must hold onto his sense of hope while navigating powerful enemies and uneasy alliances.',NULL,130,'2025-07-09','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/ldyfo0BKmz5rWtJJKCvwaNS4cJT.jpg','https://www.youtube.com/watch?v=Ox8ZLF6cGM0'),(1028,'Mission: Impossible - The Final Reckoning','Ethan Hunt and his team race to stop a terrifying AI that has infiltrated intelligence networks worldwide. With help from new allies and a connection to his past, they pursue ways to shut it down, while governments and a mysterious trail tighten the clock on whether the world changes forever.',NULL,170,'2025-05-17','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/z53D72EAOxGRqdr7KXXWp9dJiDe.jpg','https://www.youtube.com/watch?v=5WWGS2PwFB0'),(1029,'Batman Begins','After personal tragedy, a billionaire dedicates his life to fighting the corruption harming Gotham City. He travels to train with a shadowy group, then returns to confront crime by becoming a terrifying symbol to the underworld—no longer able to rely on the system.',NULL,140,'2005-06-10','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/sPX89Td70IDDjVr85jdSBb4rWGr.jpg','https://www.youtube.com/watch?v=neY2xVmOfUM'),(1030,'Batman Beyond: Return of the Joker','The Joker has returned and Neo-Gotham’s protector now faces a terrifying threat in the unfamiliar future. Standing alone, Terry must uncover what’s behind the return while the city’s safety hangs in the balance.',NULL,77,'2000-12-12','English',NULL,'PG','ACTIVE','https://image.tmdb.org/t/p/w780/cY30YkhK84E18ROghF4osi67EYT.jpg','https://www.youtube.com/watch?v=LKbJebWRrK8'),(1031,'The Conjuring','Paranormal investigators are called to a family’s farmhouse as frightening activity escalates. As they dig deeper, they confront a powerful presence that makes the case feel more dangerous than anything they’ve handled before.',NULL,112,'2013-07-18','English',NULL,'NR','ACTIVE','https://image.tmdb.org/t/p/w780/wVYREutTvI2tmxr6ujrHT704wGF.jpg','https://www.youtube.com/watch?v=k10ETZ41q5o'),(1032,'Spider-Man 2','Peter Parker hits a breaking point as he questions his life as a superhero, leaving the city to face the fallout from a dangerous new threat. Struggling to balance everyday life and complicated feelings, he also deals with anger bubbling in close relationships as the danger escalates.',NULL,127,'2004-06-25','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/aGuvNAaaZuWXYQQ6N2v7DeuP6mB.jpg','https://www.youtube.com/watch?v=1s9Yln0YwCw'),(1033,'Batman: Bad Blood','When Batman goes missing, the rest of Gotham’s Bat “family,” including Batwoman and Batwing, steps in to keep the peace. As they search for answers, they unravel the mystery behind his disappearance and face a dangerous threat targeting their home.',NULL,74,'2016-01-19','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/ktjbGsGm5GKlHDvvwQajXvDW2BN.jpg','https://www.youtube.com/watch?v=G-0bQpHlpdQ'),(1034,'Superman: Man of Tomorrow','Metropolis meets its first new hero as a young reporter-in-training secretly begins using alien powers to protect the city. As he tries to balance an ordinary life with extraordinary responsibilities, bigger threats start to emerge and force him to step up.',NULL,87,'2020-08-23','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/n9GtiJiBETVFayQy7YnVdF9AucU.jpg','https://www.youtube.com/watch?v=weOF9_FGjOk'),(1035,'Mission: Impossible - Ghost Protocol','A top agent and his team race worldwide to stop a terrorist from using stolen nuclear launch codes to strike the United States. When an attempt to end the threat goes badly and their organization is implicated, they’re cut off from government support and must keep chasing before disaster hits.',NULL,133,'2011-12-07','English',NULL,'NR','ACTIVE','https://image.tmdb.org/t/p/w780/eRZTGx7GsiKqPch96k27LK005ZL.jpg','https://www.youtube.com/watch?v=pXwaKB7YOjw'),(1036,'The Conjuring 2','Lorraine and Ed Warren travel to north London to help a single mother raising four children alone in a house plagued by malicious spirits. As unsettling events escalate, their investigations raise questions and force the family to confront what may be behind the disturbances.',NULL,134,'2016-06-08','English',NULL,'NR','ACTIVE','https://image.tmdb.org/t/p/w780/zEqyD0SBt6HL7W9JQoWwtd5Do1T.jpg','https://www.youtube.com/watch?v=VFsmuRPClr4'),(1037,'Avatar: Fire and Ash','After a devastating war and the loss of a family member, a family on Pandora must face a new threat from a violent, power-hungry tribe. As the conflict escalates, they fight to survive and to protect the future of their world, pushed to emotional and physical limits.',NULL,198,'2025-12-17','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/bRBeSHfGHwkEpImlhxPmOcUsaeg.jpg','https://www.youtube.com/watch?v=nb_fFj_0rq8'),(1038,'Superman II: The Richard Donner Cut','Superman agrees to sacrifice his powers to pursue a relationship with Lois Lane, not realizing that three Kryptonian criminals he inadvertently released are setting their sights on Earth. Their return sparks escalating conflict as Superman confronts both personal stakes and an alien takeover.',NULL,116,'2006-11-02','English',NULL,'PG','ACTIVE','https://image.tmdb.org/t/p/w780/dkLplIwss7Jleh82NawyGyFNMgJ.jpg','https://www.youtube.com/watch?v=jxD8RlGnP64'),(1039,'Batman: Hush','A new villain called Hush targets Batman by using a rotating roster of enemies to damage his crime-fighting reputation and personal life. Meanwhile, Bruce Wayne’s world grows more complicated as his relationship with Catwoman deepens.',NULL,82,'2019-07-19','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/eiVQORVyVuNNZHPAELuWtlXoQsD.jpg','https://www.youtube.com/watch?v=cQFFnUg0u70'),(1040,'Avengers: Age of Ultron','When a peacekeeping program goes wrong, Earth’s heroes face a rapidly growing threat that puts everything at risk. As a dangerous new enemy emerges, the team must stop its plans while working through uneasy alliances, leading to a high-stakes global adventure.',NULL,141,'2015-04-22','English',NULL,'NR','ACTIVE','https://image.tmdb.org/t/p/w780/4ssDuvEDkSArWEdyBl2X5EHvYKU.jpg','https://www.youtube.com/watch?v=tmeOjFno6Do'),(1041,'Superman: Unbound','Superman and Supergirl team up to stop Brainiac, a cybernetic threat claiming he has the knowledge and strength of 10,000 worlds. As Brainiac challenges their world, action and high-stakes conflict follow for the heroes.',NULL,75,'2013-04-23','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/nnZKtmVSnueWd4pjk1BekLJxXRL.jpg','https://www.youtube.com/watch?v=MPjjxhWwiyk'),(1042,'Batman: Assault on Arkham','Batman races to stop a bomb tied to the Joker, while Amanda Waller launches her newly formed team on a dangerous mission to infiltrate Arkham Asylum. Their goal is to retrieve critical information stolen by the Riddler, even as things spiral out of control.',NULL,76,'2014-08-12','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/b9KxvIAZkl2f57kjObj8Z9z9LhL.jpg','https://www.youtube.com/watch?v=-6abltUcric'),(1043,'Spider-Man','After being bitten by a genetically altered spider at Oscorp, a nerdy high school student gains amazing powers and sets out to become the superhero known as Spider-Man. Along the way, personal choices and larger-than-life villains test what it really means to be responsible.',NULL,121,'2002-05-01','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/kjdJntyBeEvqm9w97QGBdxPptzj.jpg','https://www.youtube.com/watch?v=t06RUxPbp_c'),(1044,'Superman: Red Son','Set during the Cold War, this version of Superman begins life in the USSR and grows into a powerful Soviet symbol. As he rises to prominence, his ideals collide with the real costs of maintaining a hardened political system, reshaping the meaning of heroism.',NULL,84,'2020-02-24','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/frSfz7olCSQsp2SmTyu2ciGGQiX.jpg','https://www.youtube.com/watch?v=n0s0FJfyqGk'),(1045,'Godzilla vs. Destoroyah','Godzilla is in a dangerous state, and his condition threatens disaster as he heads toward Hong Kong. At the same time, strange crustacean-like creatures begin appearing in Japan, raising fears that an old weapon may have created a new menace.',NULL,103,'1995-12-09','Japanese',NULL,'NR','ACTIVE','https://image.tmdb.org/t/p/w780/csebMf1IWokaWOughl5s3uX8p44.jpg','https://www.youtube.com/watch?v=mcJZJ1Flauc'),(1046,'Batman: Mask of the Phantasm','Andrea Beaumont returns to Gotham and rekindles a past connection with Bruce Wayne. Meanwhile, a mysterious figure targets Gotham’s criminals, putting Batman in the crosshairs and forcing him to investigate while staying one step ahead of the law and balancing his relationship.',NULL,76,'1993-12-25','English',NULL,'PG','ACTIVE','https://image.tmdb.org/t/p/w780/hT4ehUteagUrhUOHAtmYiY7mp5l.jpg','https://www.youtube.com/watch?v=imtYrQEZ4H8'),(1047,'Godzilla vs. Kong','When monsters roam the Earth, humanity must push forward for its future as two legendary titans collide. Their rivalry turns into a massive showdown that pits the mightiest forces of nature against each other, with the planet caught in the middle.',NULL,114,'2021-03-24','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/pgqgaUx1cJb5oZQQ5v0tNARCeBp.jpg','https://www.youtube.com/watch?v=odM92ap8_c0'),(1048,'Batman: Gotham by Gaslight','In an alternative Victorian Gotham City, Batman launches his war on crime while tracking a string of murders linked to Jack the Ripper. As panic grows, he investigates the killings and follows clues to uncover what—and who—drives the terror.',NULL,78,'2018-01-12','English',NULL,'R','ACTIVE','https://image.tmdb.org/t/p/w780/7souLi5zqQCnpZVghaXv0Wowi0y.jpg','https://www.youtube.com/watch?v=TJ6EX6zX4FU'),(1049,'Superman vs. The Elite','The Man of Steel faces a new wave of ruthless superheroes who challenge his ideals and disregard his moral code. As their actions raise serious questions about justice, he must push back against a threat that aims to reshape what heroism means.',NULL,76,'2012-06-12','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/6yKW9NVcqySQKa9gVe7GG3WuE9N.jpg','https://www.youtube.com/watch?v=rX8aBuz099M'),(1050,'Mission: Impossible III','Retired from active duty, an agent who trains new recruits is pulled back into the field when a ruthless international arms broker threatens everything he cares about. As the operation tightens, the agent must stop a dangerous scheme that targets his personal life.',NULL,126,'2006-04-25','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/vKGYCpmQyV9uHybWDzXuII8Los5.jpg','https://www.youtube.com/watch?v=rl2bysiyltg'),(1051,'Batman','After witnessing his parents’ murder, a wealthy vigilante battles crime in Gotham City as a feared masked hero. When a ruthless villain takes over the criminal underworld, the hero must confront his deadliest enemy while guarding his identity and dealing with his relationship with a reporter.',NULL,126,'1989-06-21','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/cij4dd21v2Rk2YtUQbV5kW69WB2.jpg','https://www.youtube.com/watch?v=dgC9Q0uhX70'),(1052,'Godzilla','Ford Brody is pulled from family life in San Francisco to help his estranged father in Japan, only for a rising threat to ignite an escalating global crisis. Ancient, colossal creatures surge from the sea, unleash devastating destruction, and push their way toward a final showdown in San Francisco.',NULL,123,'2014-05-14','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/tphkjmQq8WebuVwNXelmjLUXuPJ.jpg','https://www.youtube.com/watch?v=vIu85WQTPRc'),(1053,'Batman Returns','Beneath Gotham, a monstrous figure from the sewers teams up with a corrupt mayoral contender to bring down Batman once and for all. When a timid assistant is pushed too far, she emerges as Catwoman, joining forces in a chaotic campaign that pulls at loyalties and sparks unexpected tension.',NULL,126,'1992-06-19','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/jKBjeXM7iBBV9UkUcOXx3m7FSHY.jpg','https://www.youtube.com/watch?v=8txDV2tYtJk'),(1054,'The Conjuring: Last Rites','Paranormal investigators Ed and Lorraine Warren take on one last case involving mysterious entities that threaten a family and push them to confront what’s coming. As the haunting escalates, the investigators’ final efforts turn into a battle of endurance and fear.',NULL,136,'2025-09-03','English',NULL,'R','ACTIVE','https://image.tmdb.org/t/p/w780/byWgphT74ClOVa8EOGzYDkl8DVL.jpg','https://www.youtube.com/watch?v=FSAz556s0fM'),(1055,'Batman Ninja','Batman and many familiar allies and enemies are swept into feudal Japan by Gorilla Grodd’s time-displacement machine. Once there, the story spirals into a nonstop clash filled with big action set pieces and wildly mismatched forces.',NULL,85,'2018-03-24','Japanese',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/5xSB0Npkc9Fd9kahKBsq9P4Cdzp.jpg','https://www.youtube.com/watch?v=08dHXfIprYE'),(1056,'Godzilla, Mothra and King Ghidorah: Giant Monsters All-Out Attack','Japan fears a fresh nightmare after the destruction of a US submarine, and a reluctant family member sets out to uncover a legend of guardian monsters. As vengeful spirits draw Godzilla back into the world, the guardians must rise to protect the nation and its people.',NULL,105,'2001-12-15','Japanese',NULL,'NR','ACTIVE','https://image.tmdb.org/t/p/w780/d3lMCQJfjCBlGFy5sWpsEaBnEPl.jpg',NULL),(1057,'Batman: Gotham Knight','Six connected shorts trace Bruce Wayne’s earliest days as Batman, showing the steps that shape him into Gotham’s grim protector. Each story reveals a different angle on how he fights crime and what drives him as he grows into the role.',NULL,76,'2008-07-08','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/3i1o0sHBP0VUpuSVmkdCRKYoDBC.jpg','https://www.youtube.com/watch?v=0beX8b4zX5E'),(1058,'Superman II','Three powerful criminals from Superman’s home world arrive on Earth and join forces with a notorious mastermind, putting the planet in danger. As the threat grows, Superman faces a personal choice that leaves him vulnerable, forcing him to find a way to reclaim what he’s lost and protect the people he loves.',NULL,127,'1980-12-04','English',NULL,'PG','ACTIVE','https://image.tmdb.org/t/p/w780/3xk5cno9BHcnwc97XO9k21aI1Zi.jpg','https://www.youtube.com/watch?v=jxD8RlGnP64'),(1059,'Mission: Impossible','After a disastrous operation, a top spy is suddenly blamed for the failure and must clear their name. With suspicion everywhere, they hunt for the real double agent and race to keep a sensitive list from falling into enemy hands, even as the mission spirals through multiple locations.',NULL,111,'1996-05-22','English',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/l5uxY5m5OInWpcExIpKG6AR3rgL.jpg','https://www.youtube.com/watch?v=wb49-oV0F78'),(1060,'Godzilla: Planet of the Monsters','A desperate group of refugees tries to recolonize Earth after a long-ago takeover by a towering monster. As they struggle to rebuild, one young man is driven by revenge, pushing the mission toward confrontation rather than healing.',NULL,89,'2017-11-17','Japanese',NULL,'PG-13','ACTIVE','https://image.tmdb.org/t/p/w780/hAuZ7g6TqDLv5fOqXIPgYRguOkm.jpg','https://www.youtube.com/watch?v=_FAM_nhr_Vg');
