  KEY `idx_showtime_movie` (`movie_id`),
  KEY `idx_showtime_room_time` (`room_id`,`start_time`,`end_time`),
  KEY `idx_showtime_status` (`status`),
  KEY `idx_showtime_price` (`price`),
  CONSTRAINT `fk_showtime_movie` FOREIGN KEY (`movie_id`) REFERENCES `movie` (`movie_id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_showtime_room` FOREIGN KEY (`room_id`) REFERENCES `room` (`room_id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `chk_showtime_price` CHECK ((`price` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=80240 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
